mapper.select:
/* MenuManageMapper.selectByMenuId */
SELECT 
FROM SMS.TB_MENU A
WHERE A.MENU_ID = #{menuId,jdbcType=VARCHAR}

/* MenuManageMapper.countByUrlExceptMenuId */
SELECT COUNT(1)
FROM SMS.TB_MENU A
WHERE A.MENU_URL = #{menuUrl,jdbcType=VARCHAR}
  AND A.MENU_ID  <>  #{menuId,jdbcType=VARCHAR}

/* MenuManageMapper.countChildren */
SELECT COUNT(1)
FROM SMS.TB_MENU A
WHERE A.PARENT_MENU_ID = #{parentMenuId,jdbcType=VARCHAR}

mapper.delete:
/* MenuManageMapper.deleteMenuAuthByMenuId */
DELETE FROM SMS.TB_MENU_AUTH
 WHERE MENU_ID = #{menuId,jdbcType=VARCHAR}
